180	function normalizeExecutionStatus(value: unknown): ExecutionStatus | null {
181	    if (typeof value !== 'string') return null;
182	    const normalized = value.trim().toUpperCase();
183	    if (normalized === 'COMPLETED') return 'COMPLETED';
184	    if (normalized === 'FAILED') return 'FAILED';
185	    return null;
186	}
