188	function normalizeStatusOrigin(value: unknown): StatusOrigin | null {
189	    if (typeof value !== 'string') return null;
190	    const normalized = value.trim().toLowerCase();
191	    if (normalized === 'explicit') return 'explicit';
192	    if (normalized === 'inferred_from_success') return 'inferred_from_success';
193	    if (normalized === 'inferred_from_score') return 'inferred_from_score';
194	    if (normalized === 'reconciled_feedback') return 'reconciled_feedback';
195	    return null;
196	}
