198	function normalizeFailureToken(value: string | null | undefined, maxLen: number): string | null {
199	    if (!value) return null;
200	    const normalized = sanitizeString(value, maxLen)
201	        .trim()
202	        .toLowerCase()
203	        .replace(/\s+/g, '_')
204	        .replace(/[^a-z0-9_]/g, '_')
205	        .replace(/_+/g, '_')
206	        .replace(/^_+|_+$/g, '');
207	    if (!normalized) return null;
208	    return normalized.slice(0, maxLen);
209	}
