351	function deterministicUuidFromSeed(seed: string): string {
352	    const chars = crypto.createHash('sha256').update(seed).digest('hex').slice(0, 32).split('');
353	    // RFC 4122 version + variant bits
354	    chars[12] = '5';
355	    const variantNibble = Number.parseInt(chars[16], 16);
356	    chars[16] = ((variantNibble & 0x3) | 0x8).toString(16);
357	    const hex = chars.join('');
358	    return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
359	}
