478	                environment: environment ?? null,
479	                customer_tier: customerTier ?? null,
480	            },
481	            { onConflict: 'customer_id,issue_type,environment', ignoreDuplicates: false }
482	        )
483	        .select('context_id')
484	        .maybeSingle();
485	
486	    if (error) throw new Error(`CONTEXT_ERROR:${error.message}`);
487	
488	    if (!ctx?.context_id) {
489	        const { data: existing } = await supabase
490	            .from('dim_contexts')
491	            .select('context_id')
492	            .eq('customer_id', customerId)
493	            .eq('issue_type', issueType)
494	            .eq('environment', environment ?? null)
495	            .maybeSingle();
496	        if (existing?.context_id) return existing.context_id;
497	        throw new Error('CONTEXT_ERROR:No context_id returned after upsert');
498	    }
499	    return ctx.context_id;
