647	export function resolveTaskName(
648	    providedTaskName: string | null | undefined,
649	    issueType: string,
650	): TaskInferResult {
651	    const rawTask = providedTaskName?.trim() || null;
652	    if (rawTask) {
653	        const normalized = validateTaskName(rawTask);
654	        if (!isGenericTaskName(normalized)) {
655	            return {
656	                task: normalized,
657	                confidence: TASK_MAPPING_CONFIDENCE.developer_provided,
658	                tier: 'developer_provided',
659	            };
660	        }
661	        // Generic placeholder — try issue_type instead
662	        const inferred = inferTask(issueType);
663	        if (inferred.tier !== 'unknown') return inferred;
664	        return {
665	            task: normalized,
666	            confidence: TASK_MAPPING_CONFIDENCE.slugified_fallback,
667	            tier: 'slugified_fallback',
668	        };
669	    }
670	    return inferTask(issueType);
671	}
