677	export async function insertOutcomeRecord(
678	    insertPayload: Record<string, unknown>,
679	): Promise<{ outcomeId: string; timestamp: string }> {
680	    const { data: outcome, error: insertErr } = await supabase
681	        .from('fact_outcomes')
682	        .insert(insertPayload)
683	        .select('outcome_id, timestamp')
684	        .single();
685	
686	    if (insertErr || !outcome) {
687	        const message = insertErr?.message ?? 'Unknown insert error';
688	        const migrationHint = /column .* does not exist/i.test(message)
689	            ? ' Run missing schema migrations before retrying the ingest path.'
690	            : '';
691	        throw new Error(`INSERT_ERROR:${message}${migrationHint}`);
692	    }
693	
694	    return {
695	        outcomeId: outcome.outcome_id,
696	        timestamp: typeof outcome.timestamp === 'string' ? outcome.timestamp : new Date().toISOString(),
697	    };
698	}
