728	    // 2. Idempotency check
729	    if (row.idempotency_key) {
730	        const existing = await checkIdempotency(row.idempotency_key, customerId);
731	        if (existing) {
732	            const replayRequestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
733	            const replayExecutionStatus: ExecutionStatus = replayRequestedStatus
734	                ?? (row.success ? 'COMPLETED' : 'FAILED');
735	            const replayStatusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
736	                ?? (replayRequestedStatus ? 'explicit' : 'inferred_from_success');
737	
738	            // Return existing outcome — no duplicate insert
739	            return {
740	                outcomeId: existing,
741	                actionId: '', // Not available for idempotent replays
742	                timestamp: new Date().toISOString(),
