744	                    data_quality: 1.0,
745	                    score_origin: 'provided',
746	                    is_inconsistent: false,
747	                    mapping_tier: 'idempotent_replay',
748	                    mapping_confidence: 1.0,
749	                    inference_confidence: null,
750	                    outcome_class: null,
751	                    execution_status: replayExecutionStatus,
752	                    status_origin: replayStatusOrigin,
753	                },
754	            };
755	        }
756	    }
757	
758	    // 3. Verification — reconstruct VerifierSignal from NormalizedOutcomeRow fields.
759	    // The sync path gets verifier_signal from the SDK body directly (log-outcome.ts:1203).
760	    // The queued path stores it as verifier_source/verifier_value in the NormalizedOutcomeRow.
761	    // Both paths must apply the same hallucination correction logic.
762	    const verifierSignal = row.verifier_source
763	        ? { source: row.verifier_source as any, value: row.verifier_value ?? undefined }
764	        : undefined;
765	    const verification = resolveVerifiedSuccess(row.success, row.outcome_score ?? null, verifierSignal);
766	
767	    const computedOutcomeScoreRaw: number | null =
768	        row.outcome_score !== undefined && row.outcome_score !== null
769	            ? Math.max(0, Math.min(1, row.outcome_score))
770	            : null;
771	
772	    const computedFinalSuccess = verification.verified_success;
773	    const computedFinalOutcomeScore: number | null =
