777	
778	    const finalSuccess = opts.precomputed?.finalSuccess ?? computedFinalSuccess;
779	    const finalOutcomeScore = opts.precomputed?.finalOutcomeScore ?? computedFinalOutcomeScore;
780	    const outcomeScoreRaw = opts.precomputed?.outcomeScoreRaw ?? computedOutcomeScoreRaw;
781	    const scoreOrigin: 'provided' | 'inferred' =
