246	function normalizeTaskSlug(value: string): string {
247	    return value
248	        .trim()
249	        .toLowerCase()
250	        .replace(/[\s\-]+/g, '_')
251	        .replace(/[^a-z0-9_]/g, '')
252	        .replace(/^_+|_+$/g, '');
