259	function toUniqueTaskCandidates(values: Array<string | null | undefined>): string[] {
260	    const seen = new Set<string>();
261	    const out: string[] = [];
262	
263	    for (const value of values) {
264	        if (!value) continue;
265	        const trimmed = value.trim();
266	        if (!trimmed || seen.has(trimmed)) continue;
267	        seen.add(trimmed);
268	        out.push(trimmed);
269	    }
270	
271	    return out;
272	}
