1	import { Context, Next } from 'hono';
2	import crypto from 'node:crypto';
3	
4	import { supabase } from '../lib/supabase.js';
5	import { OUTCOME_INGEST_WORKER_BYPASS_HEADER } from '../lib/outcome-ingest-queue.js';
6	
7	const DEFAULT_WINDOW_MS = 60_000;
8	const DEFAULT_MAX_REQUESTS = 300;
9	const DEFAULT_FAIL_OPEN = false; // fail-closed: return 429 when DB is unavailable
10	
11	// Two-tier defaults for MCP gateway endpoints
12	const DEFAULT_TOOLS_LIST_MAX = 60;   // tools/list — cached, shouldn't hit often
13	const DEFAULT_TOOLS_CALL_MAX = 600;  // tools/call — each action is a call
14	
15	function readPositiveInt(value: string | undefined, fallback: number): number {
16	    const parsed = Number.parseInt(value ?? '', 10);
17	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
18	    return parsed;
19	}
20	
21	function getWindowMs(): number {
22	    return readPositiveInt(process.env.RATE_LIMIT_WINDOW_MS, DEFAULT_WINDOW_MS);
23	}
24	
25	function getMaxRequests(): number {
26	    return readPositiveInt(process.env.RATE_LIMIT_MAX, DEFAULT_MAX_REQUESTS);
27	}
28	
29	function getToolsListMax(): number {
30	    return readPositiveInt(process.env.RATE_LIMIT_TOOLS_LIST_MAX, DEFAULT_TOOLS_LIST_MAX);
31	}
32	
33	function getToolsCallMax(): number {
34	    return readPositiveInt(process.env.RATE_LIMIT_TOOLS_CALL_MAX, DEFAULT_TOOLS_CALL_MAX);
35	}
36	
37	/** Resolve the rate limit ceiling for a request path. */
38	function resolveMaxRequests(path: string): number {
39	    if (path.includes('/tools/list') || path.includes('/v2/scores') || path.includes('/v2/policy')) {
40	        return getToolsListMax();
41	    }
42	    if (path.includes('/tools/call') || path.includes('/v2/outcomes') || path.includes('/v2/recommend')) {
43	        return getToolsCallMax();
44	    }
45	    return getMaxRequests();
46	}
47	
48	function readBoolean(value: string | undefined, fallback: boolean): boolean {
49	    if (!value) return fallback;
50	    const normalized = value.trim().toLowerCase();
51	    if (['1', 'true', 'yes', 'on'].includes(normalized)) return true;
52	    if (['0', 'false', 'no', 'off'].includes(normalized)) return false;
53	    return fallback;
54	}
55	
56	function shouldFailOpen(): boolean {
57	    return readBoolean(process.env.RATE_LIMIT_FAIL_OPEN, DEFAULT_FAIL_OPEN);
58	}
59	
60	function normalizeTier(value: unknown): string {
61	    const normalized = String(value ?? '').trim().toLowerCase();
62	    if (normalized === 'free' || normalized === 'pro' || normalized === 'enterprise') {
63	        return normalized;
64	    }
65	    return 'pro';
66	}
67	
68	function buildBucketKey(customerId: string): string {
69	    return crypto
70	        .createHash('sha256')
71	        .update(`customer:${customerId}`)
72	        .digest('hex');
73	}
74	
75	interface ConsumeRateLimitRow {
76	    allowed?: boolean;
77	    retry_after_ms?: number;
78	}
79	
80	async function consumeRateLimitBucket(params: {
81	    customerId: string;
82	    customerTier: string;
83	    windowMs: number;
84	    maxRequests: number;
85	}): Promise<{ allowed: boolean; retryAfterMs: number }> {
86	    const { data, error } = await supabase.rpc('consume_rate_limit_bucket', {
87	        p_bucket_key: buildBucketKey(params.customerId),
88	        p_window_ms: params.windowMs,
89	        p_max_requests: params.maxRequests,
90	        p_tier: params.customerTier,
91	    });
92	
93	    if (error) {
94	        throw new Error(error.message);
95	    }
96	
97	    const first = Array.isArray(data)
98	        ? (data[0] as ConsumeRateLimitRow | undefined)
99	        : (data as ConsumeRateLimitRow | null);
100	
101	    if (!first || typeof first.allowed !== 'boolean') {
102	        throw new Error('Rate limiter RPC returned invalid payload');
103	    }
104	
105	    return {
106	        allowed: first.allowed,
107	        retryAfterMs: Math.max(0, Number(first.retry_after_ms ?? 0)),
108	    };
109	}
110	
111	export function __resetRateLimitStateForTests(): void {
112	    // no-op: DB-backed limiter has no in-process bucket state.
113	}
114	
115	export const rateLimitMiddleware = async (c: Context, next: Next): Promise<Response | void> => {
116	    // Internal Queue Loopback natively bypasses rate limiting, because the initial external request
117	    // that populated the array was already organically authenticated and rate-limited.
118	    if ((c.req.header(OUTCOME_INGEST_WORKER_BYPASS_HEADER) ?? '').trim() === '1') {
119	        await next();
120	        return;
121	    }
122	
123	    const customerId = c.get('customer_id') as string | undefined;
124	    const customerTier = normalizeTier(c.get('customer_tier') as string | undefined);
125	
126	    // Auth middleware handles missing customer context.
127	    if (!customerId) {
128	        await next();
129	        return;
130	    }
131	
132	    const windowMs = getWindowMs();
133	    const maxRequests = resolveMaxRequests(c.req.path);
134	
135	    try {
136	        const consumeResult = await consumeRateLimitBucket({
137	            customerId,
138	            customerTier,
139	            windowMs,
140	            maxRequests,
141	        });
142	
143	        if (consumeResult.allowed) {
144	            await next();
145	            return;
146	        }
147	
148	        const retryAfterMs = consumeResult.retryAfterMs > 0
149	            ? consumeResult.retryAfterMs
150	            : windowMs;
151	        const retryAfterSeconds = Math.max(1, Math.ceil(retryAfterMs / 1000));
152	
153	        c.header('Retry-After', String(retryAfterSeconds));
154	        return c.json(
155	            {
156	                error: 'RATE_LIMIT_EXCEEDED',
157	                message: `Too many requests. Limit: ${maxRequests}/min per customer.`,
158	                retry_after_ms: retryAfterMs,
159	            },
160	            429
161	        );
162	    } catch (err: any) {
163	        if (shouldFailOpen()) {
164	            console.warn('[rate-limit] backend unavailable, fail-open enabled:', err?.message ?? 'unknown error');
165	            await next();
166	            return;
167	        }
168	
169	        // Fail-closed: return 429 to protect the system when DB is unavailable
170	        console.error('[rate-limit] backend unavailable, fail-closed — returning 429:', err?.message ?? 'unknown error');
171	        c.header('Retry-After', '60');
172	        return c.json(
173	            {
174	                error: 'RATE_LIMIT_UNAVAILABLE',
175	                message: 'Too many requests — rate limiter is temporarily unavailable.',
176	            },
177	            429,
178	        );
179	    }
180	};
