33	  details?: unknown;
34	}
35	
36	export interface LIApiResponse<T> {
37	  ok: true;
38	  status: number;
39	  data: T;
40	}
41	
42	export interface LIApiErrorResponse {
43	  ok: false;
44	  status: number;
45	  error: LIApiError;
46	}
47	
48	export type LIResult<T> = LIApiResponse<T> | LIApiErrorResponse;
