70	// ══════════════════════════════════════════════════════════════
71	// createGatewayServer
72	// ══════════════════════════════════════════════════════════════
73	
74	export interface GatewayServer {
75	  server: Server;
76	  proxy: GatewayProxy;
77	  config: GatewayConfig;
78	  upstreamClient: UpstreamMCPClient;
79	  registry: UpstreamRegistry;
80	}
81	
82	export function createGatewayServer(): GatewayServer {
83	  const config = loadConfig();
84	  const registry = new UpstreamRegistry(config);
85	  const liApi = new LiApiClient(config);
86	  const upstreamClient = new UpstreamMCPClient(registry);
87	  const proxy = new GatewayProxy(liApi, upstreamClient, registry, config);
88	
89	  const server = new Server(
90	    { name: SERVER_NAME, version: SERVER_VERSION },
91	    { capabilities: { tools: {}, resources: {}, prompts: {} } },
92	  );
93	
94	  const startedAt = Date.now();
95	
96	  // ── tools/list ──────────────────────────────────────────
97	
98	  server.setRequestHandler(ListToolsRequestSchema, async (request) => {
99	    try {
100	      const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
101	      const enriched = await proxy.handleListTools(taskCtx);
102	
103	      // Strip internal fields (upstreamName, annotations) per MCP spec
104	      const tools = enriched.map((t) => ({
105	        name: t.name,
106	        description: t.description,
107	        inputSchema: t.inputSchema,
108	      }));
109	
110	      return { tools };
111	    } catch (err) {
112	      log.error('tools/list handler failed', {
113	        error: err instanceof Error ? err.message : String(err),
114	      });
115	      return { tools: [] };
116	    }
117	  });
118	
119	  // ── tools/call ──────────────────────────────────────────
120	
121	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
122	    const toolName = request.params?.name ?? '';
123	    const args = (request.params?.arguments ?? {}) as Record<string, unknown>;
124	    const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
125	
126	    try {
127	      const result = await proxy.handleCallTool(toolName, args, taskCtx);
128	      return result as unknown as { content: Array<{ type: string; text?: string }>; isError?: boolean };
129	    } catch (err) {
130	      const message = err instanceof Error ? err.message : String(err);
131	      log.error('tools/call handler failed', { tool: toolName, error: message });
132	      return {
133	        content: [{ type: 'text' as const, text: message }],
134	        isError: true,
135	      };
136	    }
137	  });
138	
139	  // ── resources/list ──────────────────────────────────────
140	
141	  server.setRequestHandler(
142	    { method: 'resources/list' } as never,
143	    async () => {
144	      try {
145	        const entries = registry.getAllUpstreams();
146	        const healthyCount = entries.filter((e) => registry.isHealthy(e.server.name)).length;
147	
148	        const resources = [
149	          {
150	            uri: 'li://gateway/status',
151	            name: 'Gateway Status',
152	            description: 'LayerInfinite Gateway Proxy runtime status',
153	            mimeType: 'text/plain',
154	          },
155	        ];
156	
157	        if (config.adminKey) {
158	          resources.push({
159	            uri: 'li://gateway/config',
160	            name: 'Gateway Configuration',
161	            description: 'Gateway config summary (requires admin key to read)',
162	            mimeType: 'application/json',
163	          });
164	        }
165	
166	        return { resources };
167	      } catch (err) {
168	        log.error('resources/list failed', { error: err instanceof Error ? err.message : String(err) });
169	        return { resources: [] };
170	      }
171	    },
172	  );
173	
174	  // ── resources/read ──────────────────────────────────────
175	
176	  server.setRequestHandler(
177	    { method: 'resources/read' } as never,
178	    async (request: { params?: { uri?: string } }) => {
179	      const uri = request.params?.uri ?? '';
180	
181	      try {
182	        if (uri === 'li://gateway/status') {
183	          const entries = registry.getAllUpstreams();
184	          const healthy = entries.filter((e) => registry.isHealthy(e.server.name));
185	          const uptimeMs = Date.now() - startedAt;
186	
187	          const status = {
188	            mode: config.mode ?? 'bootstrap',
189	            environment: config.environment,
190	            shadowMode: config.shadowMode,
191	            upstreams: {
192	              total: entries.length,
193	              healthy: healthy.length,
194	              names: entries.map((e) => e.server.name),
195	              healthyNames: healthy.map((e) => e.server.name),
196	            },
197	            uptime_seconds: Math.floor(uptimeMs / 1000),
198	            version: SERVER_VERSION,
199	          };
200	
201	          return {
202	            contents: [
203	              {
204	                uri,
205	                mimeType: 'text/plain',
206	                text: JSON.stringify(status, null, 2),
207	              },
208	            ],
209	          };
210	        }
211	
212	        if (uri === 'li://gateway/config') {
213	          return {
214	            contents: [
215	              {
216	                uri,
217	                mimeType: 'application/json',
218	                text: JSON.stringify(
219	                  {
220	                    mode: config.mode ?? 'bootstrap',
221	                    environment: config.environment,
222	                    shadowMode: config.shadowMode,
223	                    upstreamCount: config.upstreamServers.length,
224	                    modeOverrides: Object.fromEntries(config.modeOverrides),
225	                    apiKey: '[REDACTED]',
226	                    baseUrl: config.baseUrl,
227	                    adminEnabled: config.adminKey !== null,
228	                  },
